import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.Pywvta2k.js";const h=JSON.parse('{"title":"神农本草经","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/01-先秦两汉/04-神农本草经.md","filePath":"tcm-data/01-先秦两汉/04-神农本草经.md","lastUpdated":1781084559000}'),n={name:"tcm-data/01-先秦两汉/04-神农本草经.md"};function i(s,t,r,g,x,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="神农本草经" tabindex="-1">神农本草经 <a class="header-anchor" href="#神农本草经" aria-label="Permalink to &quot;神农本草经&quot;">​</a></h1><blockquote><p>中国现存最早的药物学专著 托名神农，实成于西汉（约公元前2-1世纪）</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：西汉，非一人一时之作</li><li><strong>载药</strong>：<strong>365种</strong>（应一年365天之数）</li><li><strong>分类</strong>：上品120种（无毒）、中品120种（有毒无毒）、下品125种（多毒）</li><li><strong>学术地位</strong>：中医四大经典之一，&quot;本草学之祖&quot;</li></ul><h3 id="三品分类法" tabindex="-1">三品分类法 <a class="header-anchor" href="#三品分类法" aria-label="Permalink to &quot;三品分类法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">数量</th><th style="text-align:left;">特点</th><th style="text-align:left;">举例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上品</strong></td><td style="text-align:left;">120</td><td style="text-align:left;">无毒，可久服，轻身延年</td><td style="text-align:left;">人参、甘草、地黄、山药、大枣、枸杞</td></tr><tr><td style="text-align:left;"><strong>中品</strong></td><td style="text-align:left;">120</td><td style="text-align:left;">无毒或有毒，斟酌使用</td><td style="text-align:left;">当归、麻黄、葛根、黄芩、芍药</td></tr><tr><td style="text-align:left;"><strong>下品</strong></td><td style="text-align:left;">125</td><td style="text-align:left;">多毒，不可久服，专攻病邪</td><td style="text-align:left;">附子、大黄、半夏、巴豆</td></tr></tbody></table><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-四气五味" tabindex="-1">1. 四气五味 <a class="header-anchor" href="#_1-四气五味" aria-label="Permalink to &quot;1. 四气五味&quot;">​</a></h3><p><strong>四气（四性）</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">气</th><th style="text-align:left;">功效</th><th style="text-align:left;">代表药</th></tr></thead><tbody><tr><td style="text-align:left;">寒</td><td style="text-align:left;">清热泻火</td><td style="text-align:left;">石膏、知母、黄芩</td></tr><tr><td style="text-align:left;">热</td><td style="text-align:left;">温里散寒</td><td style="text-align:left;">附子、干姜、肉桂</td></tr><tr><td style="text-align:left;">温</td><td style="text-align:left;">温阳散寒</td><td style="text-align:left;">桂枝、当归、黄芪</td></tr><tr><td style="text-align:left;">凉</td><td style="text-align:left;">清热兼养阴</td><td style="text-align:left;">麦冬、玄参、丹皮</td></tr></tbody></table><p><strong>五味</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">味</th><th style="text-align:left;">作用</th><th style="text-align:left;">代表药</th></tr></thead><tbody><tr><td style="text-align:left;">酸</td><td style="text-align:left;">收敛固涩</td><td style="text-align:left;">五味子、乌梅、山萸</td></tr><tr><td style="text-align:left;">苦</td><td style="text-align:left;">清热燥湿</td><td style="text-align:left;">黄连、黄芩、黄柏</td></tr><tr><td style="text-align:left;">甘</td><td style="text-align:left;">补益和中</td><td style="text-align:left;">甘草、人参、大枣</td></tr><tr><td style="text-align:left;">辛</td><td style="text-align:left;">发散行气</td><td style="text-align:left;">桂枝、麻黄、干姜</td></tr><tr><td style="text-align:left;">咸</td><td style="text-align:left;">软坚散结</td><td style="text-align:left;">牡蛎、芒硝、海藻</td></tr></tbody></table><h3 id="_2-七情配伍" tabindex="-1">2. 七情配伍 <a class="header-anchor" href="#_2-七情配伍" aria-label="Permalink to &quot;2. 七情配伍&quot;">​</a></h3><blockquote><p><strong>「药有阴阳配合，子母兄弟，根茎花实，草石骨肉。有单行者，有相须者，有相使者，有相畏者，有相恶者，有相反者，有相杀者。凡此七情，合和视之。」</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">配伍</th><th style="text-align:left;">含义</th><th style="text-align:left;">例子</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>单行</strong></td><td style="text-align:left;">单味药使用</td><td style="text-align:left;">独参汤</td></tr><tr><td style="text-align:left;"><strong>相须</strong></td><td style="text-align:left;">同类协同增效</td><td style="text-align:left;">石膏+知母</td></tr><tr><td style="text-align:left;"><strong>相使</strong></td><td style="text-align:left;">一主一辅协同</td><td style="text-align:left;">黄芪+茯苓</td></tr><tr><td style="text-align:left;"><strong>相畏</strong></td><td style="text-align:left;">甲制乙之毒</td><td style="text-align:left;">生姜制半夏毒</td></tr><tr><td style="text-align:left;"><strong>相恶</strong></td><td style="text-align:left;">甲减弱乙功效</td><td style="text-align:left;">人参恶莱菔子</td></tr><tr><td style="text-align:left;"><strong>相反</strong></td><td style="text-align:left;">合用产生毒性</td><td style="text-align:left;">十八反</td></tr><tr><td style="text-align:left;"><strong>相杀</strong></td><td style="text-align:left;">甲解乙之毒</td><td style="text-align:left;">绿豆解乌头毒</td></tr></tbody></table><hr><h2 id="三、常选药物功效速查" tabindex="-1">三、常选药物功效速查 <a class="header-anchor" href="#三、常选药物功效速查" aria-label="Permalink to &quot;三、常选药物功效速查&quot;">​</a></h2><h3 id="补益类-上品" tabindex="-1">补益类（上品） <a class="header-anchor" href="#补益类-上品" aria-label="Permalink to &quot;补益类（上品）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:left;">甘，微寒</td><td style="text-align:left;">脾、肺</td><td style="text-align:left;">大补元气，补脾益肺</td></tr><tr><td style="text-align:left;">甘草</td><td style="text-align:left;">甘，平</td><td style="text-align:left;">心、肺、脾、胃</td><td style="text-align:left;">补脾益气，调和诸药</td></tr><tr><td style="text-align:left;">地黄</td><td style="text-align:left;">甘，寒</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">滋阴养血</td></tr><tr><td style="text-align:left;">山药</td><td style="text-align:left;">甘，温</td><td style="text-align:left;">脾、肺、肾</td><td style="text-align:left;">补脾养肺，固肾益精</td></tr><tr><td style="text-align:left;">大枣</td><td style="text-align:left;">甘，平</td><td style="text-align:left;">脾、胃</td><td style="text-align:left;">补中益气，养血安神</td></tr><tr><td style="text-align:left;">枸杞</td><td style="text-align:left;">甘，平</td><td style="text-align:left;">肝、肾</td><td style="text-align:left;">滋补肝肾，益精明目</td></tr></tbody></table><h3 id="温里类-中品-下品" tabindex="-1">温里类（中品/下品） <a class="header-anchor" href="#温里类-中品-下品" aria-label="Permalink to &quot;温里类（中品/下品）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">附子</td><td style="text-align:left;">辛，温，大热，有毒</td><td style="text-align:left;">心、肾、脾</td><td style="text-align:left;">回阳救逆，补火助阳</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:left;">辛，热</td><td style="text-align:left;">脾、胃、心、肺</td><td style="text-align:left;">温中散寒，回阳通脉</td></tr><tr><td style="text-align:left;">桂枝</td><td style="text-align:left;">辛，甘，温</td><td style="text-align:left;">心、肺、膀胱</td><td style="text-align:left;">发汗解肌，温通经脉</td></tr><tr><td style="text-align:left;">肉桂</td><td style="text-align:left;">辛，甘，大热</td><td style="text-align:left;">肾、脾、心、肝</td><td style="text-align:left;">补火助阳，引火归原</td></tr></tbody></table><h3 id="清热类-中品-下品" tabindex="-1">清热类（中品/下品） <a class="header-anchor" href="#清热类-中品-下品" aria-label="Permalink to &quot;清热类（中品/下品）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">黄连</td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">心、脾、胃、肝</td><td style="text-align:left;">清热燥湿，泻火解毒</td></tr><tr><td style="text-align:left;">黄芩</td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">肺、胆、胃、大肠</td><td style="text-align:left;">清热燥湿，泻火解毒</td></tr><tr><td style="text-align:left;">黄柏</td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">肾、膀胱</td><td style="text-align:left;">清热燥湿，泻火除蒸</td></tr><tr><td style="text-align:left;">石膏</td><td style="text-align:left;">辛、甘，大寒</td><td style="text-align:left;">肺、胃</td><td style="text-align:left;">清热泻火，除烦止渴</td></tr><tr><td style="text-align:left;">知母</td><td style="text-align:left;">苦、甘，寒</td><td style="text-align:left;">肺、胃、肾</td><td style="text-align:left;">清热泻火，滋阴润燥</td></tr></tbody></table><h3 id="祛湿类" tabindex="-1">祛湿类 <a class="header-anchor" href="#祛湿类" aria-label="Permalink to &quot;祛湿类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">茯苓</td><td style="text-align:left;">甘、淡，平</td><td style="text-align:left;">心、脾、肺、肾</td><td style="text-align:left;">利水渗湿，健脾</td></tr><tr><td style="text-align:left;">泽泻</td><td style="text-align:left;">甘，寒</td><td style="text-align:left;">肾、膀胱</td><td style="text-align:left;">利水渗湿，泄热</td></tr><tr><td style="text-align:left;">白术</td><td style="text-align:left;">苦、甘，温</td><td style="text-align:left;">脾、胃</td><td style="text-align:left;">健脾益气，燥湿利水</td></tr><tr><td style="text-align:left;">苍术</td><td style="text-align:left;">辛、苦，温</td><td style="text-align:left;">脾、胃</td><td style="text-align:left;">燥湿健脾，祛风散寒</td></tr></tbody></table><h3 id="活血-养血类" tabindex="-1">活血/养血类 <a class="header-anchor" href="#活血-养血类" aria-label="Permalink to &quot;活血/养血类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">当归</td><td style="text-align:left;">甘、辛，温</td><td style="text-align:left;">肝、心、脾</td><td style="text-align:left;">补血活血，调经止痛</td></tr><tr><td style="text-align:left;">芍药</td><td style="text-align:left;">苦、酸，微寒</td><td style="text-align:left;">肝、脾</td><td style="text-align:left;">养血柔肝，缓中止痛</td></tr><tr><td style="text-align:left;">丹皮</td><td style="text-align:left;">苦、辛，微寒</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">清热凉血，活血散瘀</td></tr><tr><td style="text-align:left;">川芎</td><td style="text-align:left;">辛，温</td><td style="text-align:left;">肝、胆、心包</td><td style="text-align:left;">活血行气，祛风止痛</td></tr></tbody></table><h3 id="潜阳安神类" tabindex="-1">潜阳安神类 <a class="header-anchor" href="#潜阳安神类" aria-label="Permalink to &quot;潜阳安神类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th></tr></thead><tbody><tr><td style="text-align:left;">龙骨</td><td style="text-align:left;">甘、涩，平</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">镇惊安神，平肝潜阳</td></tr><tr><td style="text-align:left;">牡蛎</td><td style="text-align:left;">咸，微寒</td><td style="text-align:left;">肝、胆、肾</td><td style="text-align:left;">潜阳补阴，软坚散结</td></tr><tr><td style="text-align:left;">酸枣仁</td><td style="text-align:left;">甘、酸，平</td><td style="text-align:left;">肝、胆、心</td><td style="text-align:left;">养心安神，敛汗</td></tr></tbody></table><hr><h2 id="四、十八反十九畏-配伍禁忌" tabindex="-1">四、十八反十九畏（配伍禁忌） <a class="header-anchor" href="#四、十八反十九畏-配伍禁忌" aria-label="Permalink to &quot;四、十八反十九畏（配伍禁忌）&quot;">​</a></h2><h3 id="十八反" tabindex="-1">十八反 <a class="header-anchor" href="#十八反" aria-label="Permalink to &quot;十八反&quot;">​</a></h3><blockquote><p>本草明言十八反，半蒌贝蔹及攻乌 藻戟遂芫俱战草，诸参辛芍叛藜芦</p></blockquote><ul><li><strong>乌头反</strong>：半夏、瓜蒌、贝母、白蔹、白及</li><li><strong>甘草反</strong>：海藻、大戟、甘遂、芫花</li><li><strong>藜芦反</strong>：人参、沙参、丹参、玄参、细辛、芍药</li></ul><h3 id="十九畏" tabindex="-1">十九畏 <a class="header-anchor" href="#十九畏" aria-label="Permalink to &quot;十九畏&quot;">​</a></h3><blockquote><p>硫黄原是火中精，朴硝一见便相争 水银莫与砒霜见，狼毒最怕密陀僧 巴豆性烈最为上，偏与牵牛不顺情 丁香莫与郁金见，牙硝难合京三棱 川乌草乌不顺犀，人参最怕五灵脂 官桂善能调冷气，若逢石脂便相欺</p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">本草著作</th><th style="text-align:left;">与《本经》的关系</th></tr></thead><tbody><tr><td style="text-align:left;">《本草经集注》（陶弘景）</td><td style="text-align:left;">载药730种，首次按自然分类</td></tr><tr><td style="text-align:left;">《新修本草》（唐）</td><td style="text-align:left;">官方编纂，载药844种</td></tr><tr><td style="text-align:left;">《证类本草》（宋·唐慎微）</td><td style="text-align:left;">载药1558种，集宋以前大成</td></tr><tr><td style="text-align:left;">《本草纲目》（明·李时珍）</td><td style="text-align:left;">载药1892种，划时代巨著</td></tr><tr><td style="text-align:left;">《本草备要》（清·汪昂）</td><td style="text-align:left;">普及性本草，临床实用</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展为按药物功效分类的《药性速查》，以及对比《本经》与后世本草对同一药物认识的演变。</em></p>',43)])])}const o=e(n,[["render",i]]);export{h as __pageData,o as default};
